import numpy as np

def item_based_cf(ratings: np.ndarray, user: int, item: int, k: int = 3) -> float:
    target_vec = ratings[:, item].astype(float)
    candidates = []
    for i in range(ratings.shape[1]):
        if i == item or ratings[user, i] == 0:
            continue
        other_vec = ratings[:, i].astype(float)
        denom = np.linalg.norm(target_vec) * np.linalg.norm(other_vec)
        if denom == 0:
            sim = 0.0
        else:
            sim = np.dot(target_vec, other_vec) / denom
        candidates.append((sim, float(ratings[user, i])))
    if not candidates:
        return 0.0
    candidates.sort(key=lambda x: -x[0])
    top = candidates[:k]
    sim_sum = sum(abs(s) for s, _ in top)
    if sim_sum == 0:
        return 0.0
    return sum(s * r for s, r in top) / sim_sum
